SwiftUI doesn’t provide a built-in mechanism to detect device orientation changes directly. However, you can achieve this by integrating UIKit’s `UIDevice` notifications into your SwiftUI views. Here’s how you can implement this:

```swift
import SwiftUI

// Custom view modifier to track rotation and call our action
struct DeviceRotationViewModifier: ViewModifier {
    let action: (UIDeviceOrientation) -> Void

    func body(content: Content) -> some View {
        content
            .onAppear()
            .onReceive(NotificationCenter.default.publisher(for: UIDevice.orientationDidChangeNotification)) { _ in
                let currentOrientation = UIDevice.current.orientation
                if currentOrientation.isValidInterfaceOrientation {
                    action(currentOrientation)
                }
            }
    }
}

// View extension to make the modifier easier to use
extension View {
    func onRotate(perform action: @escaping (UIDeviceOrientation) -> Void) -> some View {
        self.modifier(DeviceRotationViewModifier(action: action))
    }
}

// Example view demonstrating the solution
struct ContentView: View {
    @State private var orientation = UIDeviceOrientation.unknown

    var body: some View {
        Group {
            if orientation.isPortrait {
                Text("Portrait")
            } else if orientation.isLandscape {
                Text("Landscape")
            } else if orientation.isFlat {
                Text("Flat")
            } else {
                Text("Unknown")
            }
        }
        .onAppear {
            // Fetch the current interface orientation on appear
            if let scene = UIApplication.shared.connectedScenes.first as? UIWindowScene {
                let interfaceOrientation = scene.interfaceOrientation
                switch interfaceOrientation {
                case .portrait:
                    orientation = .portrait
                case .portraitUpsideDown:
                    orientation = .portraitUpsideDown
                case .landscapeLeft:
                    orientation = .landscapeLeft
                case .landscapeRight:
                    orientation = .landscapeRight
                default:
                    orientation = .unknown
                }
            }
        }
        .onRotate { newOrientation in
            orientation = newOrientation
        }
    }
}

```

